import{_ as r,o as s,c as t,a2 as i}from"./chunks/framework.Cuq8tsM6.js";const v=JSON.parse('{"title":"Audience & Score","description":"","frontmatter":{"title":"Audience & Score"},"headers":[],"relativePath":"docs/fr/publishers/audience-setup.md","filePath":"docs/fr/publishers/audience-setup.md"}'),o={name:"docs/fr/publishers/audience-setup.md"};function a(d,e,n,p,l,c){return s(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="configuration-de-l-audience-score" tabindex="-1">Configuration de l&#39;Audience &amp; Score <a class="header-anchor" href="#configuration-de-l-audience-score" aria-label="Permalink to &quot;Configuration de l&#39;Audience &amp; Score&quot;">​</a></h1><p>Votre fiche audience est votre vitrine auprès des annonceurs. Plus elle est précise, plus vous recevrez de propositions pertinentes.</p><hr class="my-6"><h2 class="text-purple-200 mb-4">1. L&#39;Identité de votre Audience</h2><div style="display:flex;gap:20px;flex-wrap:wrap;margin-bottom:40px;"><div style="flex:1;min-width:300px;"><p class="fs-4">C&#39;est la première chose que l&#39;annonceur voit. Soignez la présentation pour déclencher le &quot;coup de cœur&quot;.</p><ul class="mb-0 fs-3 pl-4"><li class="mb-2"><strong>Présentation :</strong> Racontez votre histoire, vos valeurs et votre positionnement.</li><li class="mb-2"><strong>Engagements RSE :</strong> Cochez les cases (Made in France, Colis réutilisables...) uniquement si vous pouvez le prouver.</li><li><strong>Visuels :</strong> Uploadez un logo et une bannière qui représentent votre univers.</li></ul></div><div style="flex:1;min-width:300px;background:var(--gi-tint-blue-bg);border:2px solid var(--gi-accent);border-radius:8px;padding:24px;"><h3 class="mt-0 text-purple-200">💡 Le conseil de l&#39;équipe</h3><p class="mb-0">Dans le champ <strong>&quot;Persona&quot;</strong>, soyez descriptif : <em>&quot;Jardinier amateur ou expert cherchant des produits durables pour entretenir son potager.&quot;</em> Cela aide les annonceurs à mieux comprendre qui sont vos clients.</p></div></div><h2 class="text-blue-200 mb-4">2. Les Données Démographiques (Data)</h2><p class="fs-4">Ces champs alimentent l&#39;algorithme de getinside pour le matching.</p><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(200px, 1fr));gap:20px;margin-bottom:40px;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);"><strong>Panier Moyen</strong><p class="fs-2 text-grey-dk-000 mb-0">Indiquez le montant HT moyen. Cela permet aux annonceurs de cibler par pouvoir d&#39;achat.</p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);"><strong>Typologie (B2C/B2B)</strong><p class="fs-2 text-grey-dk-000 mb-0">Critère excluant. Assurez-vous qu&#39;il est correct.</p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);"><strong>Profil d&#39;acheteur</strong><p class="fs-2 text-grey-dk-000 mb-0"><em>Discounter, Économe, Médian, Élevé.</em> Positionnez-vous par rapport à votre marché.</p></div></div><hr class="my-6"><h2 class="text-grey-dk-000 mb-4">3. Comprendre votre &quot;Score Distributeur&quot;</h2><div style="border:2px solid var(--vp-c-text-1);background-color:var(--vp-c-bg-elv);padding:24px;border-radius:8px;margin-bottom:40px;"><div style="display:flex;align-items:center;gap:20px;margin-bottom:20px;"><div style="font-size:40px;font-weight:800;color:var(--vp-c-text-1);">4,3<span class="fs-4 text-grey-dk-000">/5</span></div><div><h3 class="mt-0 mb-0">Votre passeport pour plus de campagnes</h3><p class="fs-2 text-grey-dk-000 mb-0">Ce score est recalculé dynamiquement selon 7 critères clés. Il détermine votre position dans les résultats de recherche.</p></div></div><div class="p-3" style="background-color:var(--vp-c-bg-soft);border-radius:6px;"><strong>Barème de visibilité :</strong><ul class="mb-0 mt-2 fs-2"><li class="mb-1"><span style="color:var(--gi-tint-red-text);">●</span> <strong>Moins de 3/5 :</strong> Votre audience est peu visible. Des actions correctives sont nécessaires.</li><li class="mb-1"><span style="color:var(--gi-tint-yellow-text);">●</span> <strong>De 3 à 4/5 :</strong> Visibilité standard. Vous recevez des propositions régulièrement.</li><li><span style="color:var(--gi-tint-green-text);">●</span> <strong>Plus de 4/5 :</strong> Statut &quot;Top Distributeur&quot;. Vous apparaissez en priorité et obtenez le badge de confiance.</li></ul></div></div><h3 class="text-grey-dk-000 mb-4">Détail des 7 critères de notation</h3><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(300px, 1fr));gap:20px;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);"><strong class="text-green-200">💰 Tarification</strong><p class="fs-2 text-grey-dk-000 mb-0">L&#39;algorithme compare votre CPM (Coût Pour Mille) à la moyenne du marché sur votre secteur. Un prix cohérent booste ce score.</p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);"><strong class="text-purple-200">📈 Volume semaine (Reach)</strong><p class="fs-2 text-grey-dk-000 mb-0">Plus votre capacité de diffusion est importante et stable, plus ce score est élevé. Les volumes trop faibles peuvent impacter la note.</p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);"><strong class="text-blue-200">✨ Attractivité de la marque</strong><p class="fs-2 text-grey-dk-000 mb-0">Reflète la notoriété et la perception de votre enseigne. Plus votre marque est identifiée comme une référence (grand public ou spécialiste) sur son marché, plus ce score est élevé.</p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);"><strong class="text-red-100">📦 Fiabilité de l&#39;inventaire</strong><p class="fs-2 text-grey-dk-000 mb-0">Respectez-vous les volumes promis ? Si vous distribuez moins que prévu sans prévenir, ce score chute drastiquement.</p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);"><strong class="text-orange-200">⚡ Réactivité de l&#39;audience</strong><p class="fs-2 text-grey-dk-000 mb-0">Mesure la performance de vos campagnes passées (taux de scan, usage codes promo). Une audience engagée qui réagit aux offres fait monter ce score.</p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);"><strong class="text-grey-dk-000">📊 Historique de campagne</strong><p class="fs-2 text-grey-dk-000 mb-0">Récompense la fidélité. Ce score augmente mécaniquement avec le nombre de campagnes réussies sur la plateforme.</p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;background:var(--vp-c-bg-elv);"><strong class="text-grey-dk-000">💬 Communication &amp; Reporting</strong><p class="fs-2 text-grey-dk-000 mb-0">Évalue votre sérieux opérationnel : rapidité de réponse aux demandes (sous 48h) et envoi des preuves de distribution dans les délais.</p></div></div>',13)])])}const g=r(o,[["render",a]]);export{v as __pageData,g as default};
